-- Kawana Family Clinic: 4G Backup SIM Service = $35.00 ex GST (from Channel Haus invoice $38.50 inc GST)
UPDATE services SET monthlyCost = 35.00 WHERE externalId = 'S1043';

-- Also update the eFax services for all customers that have them
-- Albany Family Doctors eFax
UPDATE services SET monthlyCost = 35.00 WHERE externalId IN (
  SELECT externalId FROM (
    SELECT s.externalId FROM services s
    LEFT JOIN customers c ON s.customerExternalId = c.externalId
    WHERE c.name = 'Albany Family Doctors' AND s.planName LIKE '%eFax%'
  ) tmp
);

